package com.exam.controller.admin;

import com.exam.dto.QuestionBatchRequest;
import com.exam.dto.QuestionCreateRequest;
import com.exam.dto.Result;
import com.exam.entity.QuestionBank;
import com.exam.service.QuestionService;
import jakarta.validation.Valid;
import lombok.extern.slf4j.Slf4j;
import org.springframework.web.bind.annotation.*;

import java.util.List;

/**
 * 管理员 - 题目管理接口
 */
@Slf4j
@RestController
@RequestMapping("/api/admin")
public class AdminQuestionController {

    private final QuestionService questionService;

    public AdminQuestionController(QuestionService questionService) {
        this.questionService = questionService;
    }

    @GetMapping("/exams/{examId}/questions")
    public Result<List<QuestionBank>> list(@PathVariable Long examId) {
        return Result.ok(questionService.list(examId));
    }

    @PostMapping("/exams/{examId}/questions")
    public Result<QuestionBank> create(@PathVariable Long examId,
                                       @Valid @RequestBody QuestionCreateRequest req) {
        log.info("[lbl][Question][CREATE] 创建题目请求, examId={}", examId);
        return Result.ok(questionService.create(examId, req));
    }

    @PostMapping("/exams/{examId}/questions/batch")
    public Result<Integer> batchCreate(@PathVariable Long examId,
                                       @Valid @RequestBody QuestionBatchRequest req) {
        log.info("[lbl][Question][BATCH_CREATE] 批量导入题目请求, examId={}, count={}",
                examId, req.getQuestions() != null ? req.getQuestions().size() : 0);
        return Result.ok(questionService.batchCreate(examId, req));
    }

    @PutMapping("/questions/{id}")
    public Result<Void> update(@PathVariable Long id,
                               @Valid @RequestBody QuestionCreateRequest req) {
        log.info("[lbl][Question][UPDATE] 更新题目请求, questionId={}", id);
        questionService.update(id, req);
        return Result.ok();
    }

    @DeleteMapping("/questions/{id}")
    public Result<Void> delete(@PathVariable Long id) {
        log.info("[lbl][Question][DELETE] 删除题目请求, questionId={}", id);
        questionService.delete(id);
        return Result.ok();
    }
}

