 * API Token 管理服务
 */
@Slf4j
@Service
@RequiredArgsConstructor
public class ApiTokenService {

    private final ApiTokenMapper apiTokenMapper;
    private final ApiCallLogMapper apiCallLogMapper;
    private final SysUserMapper sysUserMapper;

    /**
     * 创建 Token，返回完整 token 值（仅此一次）
     */
    public ApiTokenResponse create(Long userId, ApiTokenCreateRequest req) {
        String tokenValue = UUID.randomUUID().toString().replace("-", "");
        ApiToken apiToken = ApiToken.builder()
                .token(tokenValue)
                .name(req.getName())
                .createdBy(userId)
                .enabled(true)
                .expiresAt(req.getExpiresAt())
                .build();
        apiTokenMapper.insert(apiToken);
        log.info("[lbl][ApiToken][CREATE] 创建 API Token, tokenId={}, userId={}, name={}",
                apiToken.getId(), userId, req.getName());

        SysUser user = sysUserMapper.selectById(userId);
        return ApiTokenResponse.builder()
                .id(apiToken.getId())
                .name(apiToken.getName())
                .token(tokenValue)
                .enabled(true)
                .expiresAt(apiToken.getExpiresAt())
                .createdByName(user != null ? user.getDisplayName() : null)
                .createdAt(apiToken.getCreatedAt())
                .build();
    }

    /**
     * 查询当前用户创建的所有 Token（脱敏）
     */
    public List<ApiTokenResponse> list(Long userId) {
        List<ApiToken> tokens = apiTokenMapper.selectList(
                new LambdaQueryWrapper<ApiToken>()
                        .eq(ApiToken::getCreatedBy, userId)
                        .orderByDesc(ApiToken::getCreatedAt));

        SysUser user = sysUserMapper.selectById(userId);
        String displayName = user != null ? user.getDisplayName() : null;

        return tokens.stream().map(t -> ApiTokenResponse.builder()
                .id(t.getId())
                .name(t.getName())
                .token(maskToken(t.getToken()))
                .enabled(t.getEnabled())
                .expiresAt(t.getExpiresAt())
                .createdByName(displayName)
                .createdAt(t.getCreatedAt())
                .build()).collect(Collectors.toList());
    }

    /**
     * 启用/禁用 Token
     */
    public void toggleEnabled(Long tokenId, Long userId) {
        ApiToken token = getOwnedToken(tokenId, userId);
        token.setEnabled(!token.getEnabled());
        apiTokenMapper.updateById(token);
        log.info("[lbl][ApiToken][TOGGLE] Token 状态变更, tokenId={}, enabled={}", tokenId, token.getEnabled());
    }

    /**
     * 删除 Token
     */
    public void delete(Long tokenId, Long userId) {
        getOwnedToken(tokenId, userId);
        apiTokenMapper.deleteById(tokenId);
        log.info("[lbl][ApiToken][DELETE] 删除 Token, tokenId={}, userId={}", tokenId, userId);
    }

    /**
     * 验证 token 值，返回有效的 ApiToken，无效则抛异常
     */
    public ApiToken validate(String tokenValue) {
        ApiToken token = apiTokenMapper.selectOne(
                new LambdaQueryWrapper<ApiToken>().eq(ApiToken::getToken, tokenValue));
        if (token == null) {
            throw new BizException(ErrorCode.TOKEN_INVALID);
        }
        if (!token.getEnabled()) {
            throw new BizException(ErrorCode.TOKEN_DISABLED);
        }
        if (token.getExpiresAt() != null && token.getExpiresAt().isBefore(LocalDateTime.now())) {
            throw new BizException(ErrorCode.TOKEN_EXPIRED);
        }
        return token;
    }

    /**
     * 记录 API 调用日志
     */
    public void logCall(ApiCallLog callLog) {
        apiCallLogMapper.insert(callLog);
    }

    /**
     * 查询指定 Token 的调用记录
     */
    public List<ApiCallLogResponse> listCallLogs(Long tokenId, Long userId) {
        getOwnedToken(tokenId, userId);

        ApiToken token = apiTokenMapper.selectById(tokenId);
        List<ApiCallLog> logs = apiCallLogMapper.selectList(
                new LambdaQueryWrapper<ApiCallLog>()
                        .eq(ApiCallLog::getTokenId, tokenId)
                        .orderByDesc(ApiCallLog::getCreatedAt)
                        .last("LIMIT 200"));

        return logs.stream().map(l -> ApiCallLogResponse.builder()
                .id(l.getId())
                .tokenName(token.getName())
                .requestMethod(l.getRequestMethod())
                .requestPath(l.getRequestPath())
                .requestBody(l.getRequestBody())
                .responseCode(l.getResponseCode())
                .responseBody(l.getResponseBody())
                .durationMs(l.getDurationMs())
                .clientIp(l.getClientIp())
                .createdAt(l.getCreatedAt())
                .build()).collect(Collectors.toList());
    }

    /**
     * 查询当前用户所有 Token 的调用记录
     */
    public List<ApiCallLogResponse> listAllCallLogs(Long userId) {
        List<ApiToken> tokens = apiTokenMapper.selectList(
                new LambdaQueryWrapper<ApiToken>().eq(ApiToken::getCreatedBy, userId));
        if (tokens.isEmpty()) {
            return List.of();
        }

        Map<Long, String> tokenNameMap = tokens.stream()
                .collect(Collectors.toMap(ApiToken::getId, ApiToken::getName));
        List<Long> tokenIds = tokens.stream().map(ApiToken::getId).collect(Collectors.toList());

        List<ApiCallLog> logs = apiCallLogMapper.selectList(
                new LambdaQueryWrapper<ApiCallLog>()
                        .in(ApiCallLog::getTokenId, tokenIds)
                        .orderByDesc(ApiCallLog::getCreatedAt)
                        .last("LIMIT 200"));

        return logs.stream().map(l -> ApiCallLogResponse.builder()
                .id(l.getId())
                .tokenName(tokenNameMap.getOrDefault(l.getTokenId(), ""))
                .requestMethod(l.getRequestMethod())
                .requestPath(l.getRequestPath())
                .requestBody(l.getRequestBody())
                .responseCode(l.getResponseCode())
                .responseBody(l.getResponseBody())
                .durationMs(l.getDurationMs())
                .clientIp(l.getClientIp())
                .createdAt(l.getCreatedAt())
                .build()).collect(Collectors.toList());
    }

    /**
     * 校验 Token 归属当前用户
     */
    private ApiToken getOwnedToken(Long tokenId, Long userId) {
        ApiToken token = apiTokenMapper.selectById(tokenId);
        if (token == null) {
            throw new BizException(ErrorCode.NOT_FOUND);
        }
        if (!token.getCreatedBy().equals(userId)) {
            throw new BizException(ErrorCode.FORBIDDEN);
        }
        return token;
    }

    /**
     * Token 脱敏：只显示前6位和后4位
     */
    private String maskToken(String token) {
        if (token == null || token.length() <= 10) {
            return "****";
        }
        return token.substring(0, 6) + "****" + token.substring(token.length() - 4);
    }
}

