import org.springframework.security.core.Authentication;
import org.springframework.web.bind.annotation.*;

import java.util.List;

/**
 * 管理员 - API Token 管理接口
 */
@Slf4j
@RestController
@RequestMapping("/api/admin/tokens")
@RequiredArgsConstructor
public class AdminApiTokenController {

    private final ApiTokenService apiTokenService;

    /** 创建 Token */
    @PostMapping
    public Result<ApiTokenResponse> create(Authentication auth,
                                           @Valid @RequestBody ApiTokenCreateRequest req) {
        Long userId = (Long) auth.getPrincipal();
        log.info("[lbl][ApiToken][CREATE] 创建 Token 请求, userId={}, name={}", userId, req.getName());
        return Result.ok(apiTokenService.create(userId, req));
    }

    /** 查询 Token 列表 */
    @GetMapping
    public Result<List<ApiTokenResponse>> list(Authentication auth) {
        Long userId = (Long) auth.getPrincipal();
        return Result.ok(apiTokenService.list(userId));
    }

    /** 启用/禁用 Token */
    @PutMapping("/{id}/toggle")
    public Result<Void> toggle(Authentication auth, @PathVariable Long id) {
        Long userId = (Long) auth.getPrincipal();
        log.info("[lbl][ApiToken][TOGGLE] 切换 Token 状态, tokenId={}, userId={}", id, userId);
        apiTokenService.toggleEnabled(id, userId);
        return Result.ok();
    }

    /** 删除 Token */
    @DeleteMapping("/{id}")
    public Result<Void> delete(Authentication auth, @PathVariable Long id) {
        Long userId = (Long) auth.getPrincipal();
        log.info("[lbl][ApiToken][DELETE] 删除 Token, tokenId={}, userId={}", id, userId);
        apiTokenService.delete(id, userId);
        return Result.ok();
    }

    /** 查询指定 Token 的调用记录 */
    @GetMapping("/{id}/logs")
    public Result<List<ApiCallLogResponse>> tokenLogs(Authentication auth, @PathVariable Long id) {
        Long userId = (Long) auth.getPrincipal();
        return Result.ok(apiTokenService.listCallLogs(id, userId));
    }

    /** 查询所有 Token 的调用记录 */
    @GetMapping("/logs")
    public Result<List<ApiCallLogResponse>> allLogs(Authentication auth) {
        Long userId = (Long) auth.getPrincipal();
        return Result.ok(apiTokenService.listAllCallLogs(userId));
    }
}

