import { useQuery, useMutation, useQueryClient } from "@tanstack/react-query"
import { get, post, put, del } from "@/lib/api"
import type { ApiToken, ApiCallLog } from "@/types"

const TOKENS_KEY = "admin-tokens"
const TOKEN_LOGS_KEY = "admin-token-logs"

/** 获取 Token 列表 */
export function useTokenList() {
  return useQuery<ApiToken[]>({
    queryKey: [TOKENS_KEY],
    queryFn: () => get<ApiToken[]>("/api/admin/tokens"),
  })
}

/** 创建 Token */
export function useCreateToken() {
  const queryClient = useQueryClient()
  return useMutation({
    mutationFn: (data: { name: string; expiresAt?: string | null }) =>
      post<ApiToken>("/api/admin/tokens", data),
    onSuccess: () => {
      queryClient.invalidateQueries({ queryKey: [TOKENS_KEY] })
    },
  })
}

/** 启用/禁用 Token */
export function useToggleToken() {
  const queryClient = useQueryClient()
  return useMutation({
    mutationFn: (id: number) => put<void>(`/api/admin/tokens/${id}/toggle`),
    onSuccess: () => {
      queryClient.invalidateQueries({ queryKey: [TOKENS_KEY] })
    },
  })
}

/** 删除 Token */
export function useDeleteToken() {
  const queryClient = useQueryClient()
  return useMutation({
    mutationFn: (id: number) => del<void>(`/api/admin/tokens/${id}`),
    onSuccess: () => {
      queryClient.invalidateQueries({ queryKey: [TOKENS_KEY] })
    },
  })
}

/** 查询所有调用记录 */
export function useAllCallLogs() {
  return useQuery<ApiCallLog[]>({
    queryKey: [TOKEN_LOGS_KEY],
    queryFn: () => get<ApiCallLog[]>("/api/admin/tokens/logs"),
  })
}

/** 查询指定 Token 的调用记录 */
export function useTokenCallLogs(tokenId: number | null) {
  return useQuery<ApiCallLog[]>({
    queryKey: [TOKEN_LOGS_KEY, tokenId],
    queryFn: () => get<ApiCallLog[]>(`/api/admin/tokens/${tokenId}/logs`),
    enabled: tokenId != null,
  })
}

